## Next.js (App Router)

### Server (Route Handler / Server Action) — `app/lib/opensailData.server.ts`

```ts
// Uses the non-public service key — only safe in server-side code.
const URL = process.env.OPENSAIL_DATA_API_URL!;
const KEY = process.env.OPENSAIL_DATA_KEY!;

const headers = { Authorization: `Bearer ${KEY}`, 'Content-Type': 'application/json' };

export async function insert<T extends object>(collection: string, doc: T) {
  const r = await fetch(`${URL}/${collection}`, { method: 'POST', headers, body: JSON.stringify(doc), cache: 'no-store' });
  if (!r.ok) throw new Error(`insert ${r.status}`);
  return r.json();
}

export async function list(collection: string, limit = 50, offset = 0) {
  const r = await fetch(`${URL}/${collection}?limit=${limit}&offset=${offset}`, { headers, cache: 'no-store' });
  if (!r.ok) throw new Error(`list ${r.status}`);
  return r.json();
}
```

### Client component — `app/lib/opensailData.client.ts`

```ts
'use client';
const URL = process.env.NEXT_PUBLIC_OPENSAIL_DATA_API_URL!;
const KEY = process.env.NEXT_PUBLIC_OPENSAIL_DATA_KEY!;
// ...same helper using these instead of process.env.OPENSAIL_*
```

### Route Handler example

```ts
// app/api/submissions/route.ts
import { NextResponse } from 'next/server';
import { insert, list } from '@/lib/opensailData.server';

export async function POST(req: Request) {
  const body = await req.json();
  return NextResponse.json(await insert('submissions', body));
}

export async function GET() {
  return NextResponse.json(await list('submissions'));
}
```

