## Plain HTML form (no build step)

```html
<form id="f">
  <input name="email" type="email" required />
  <textarea name="message" required></textarea>
  <button>Send</button>
  <p id="status"></p>
</form>
<script>
  // These two lines are filled in by the build / templating step from
  // OPENSAIL_DATA_API_URL and OPENSAIL_DATA_KEY env vars.
  const URL = "%%OPENSAIL_DATA_API_URL%%";
  const KEY = "%%OPENSAIL_DATA_KEY%%";

  document.getElementById('f').addEventListener('submit', async (e) => {
    e.preventDefault();
    const fd = Object.fromEntries(new FormData(e.target));
    const r = await fetch(`${URL}/submissions`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(fd),
    });
    // textContent is XSS-safe (no HTML parsing) — never use innerHTML with
    // values that could contain user input or response data.
    document.getElementById('status').textContent = r.ok ? 'Thanks!' : `Error ${r.status}`;
  });
</script>
```

