## Python (server-side) — `opensail_data.py`

```python
import os
from typing import Any

import httpx

URL = os.environ["OPENSAIL_DATA_API_URL"]
KEY = os.environ["OPENSAIL_DATA_KEY"]

_client = httpx.Client(headers={"Authorization": f"Bearer {KEY}"}, timeout=30.0)


def insert(collection: str, doc: dict[str, Any]) -> dict[str, Any]:
    r = _client.post(f"{URL}/{collection}", json=doc)
    r.raise_for_status()
    return r.json()


def list_records(collection: str, *, limit: int = 50, offset: int = 0) -> dict[str, Any]:
    r = _client.get(f"{URL}/{collection}", params={"limit": limit, "offset": offset})
    r.raise_for_status()
    return r.json()


def get(collection: str, record_id: str) -> dict[str, Any]:
    r = _client.get(f"{URL}/{collection}/{record_id}")
    r.raise_for_status()
    return r.json()


def update(collection: str, record_id: str, doc: dict[str, Any]) -> dict[str, Any]:
    r = _client.patch(f"{URL}/{collection}/{record_id}", json=doc)
    r.raise_for_status()
    return r.json()


def delete(collection: str, record_id: str) -> None:
    r = _client.delete(f"{URL}/{collection}/{record_id}")
    r.raise_for_status()
```

### FastAPI route using it

```python
from fastapi import APIRouter
from pydantic import BaseModel
from . import opensail_data as data

router = APIRouter()

class Submission(BaseModel):
    email: str
    message: str

@router.post("/submissions")
def submit(s: Submission):
    return data.insert("submissions", s.model_dump())

@router.get("/submissions")
def list_subs():
    return data.list_records("submissions")
```

