## Go (server-side) — `opensaildata/client.go`

```go
package opensaildata

import (
    "bytes"
    "encoding/json"
    "fmt"
    "io"
    "net/http"
    "os"
)

var (
    URL = os.Getenv("OPENSAIL_DATA_API_URL")
    KEY = os.Getenv("OPENSAIL_DATA_KEY")
)

func do(method, path string, body any) ([]byte, int, error) {
    var rdr io.Reader
    if body != nil {
        b, _ := json.Marshal(body)
        rdr = bytes.NewReader(b)
    }
    req, _ := http.NewRequest(method, URL+path, rdr)
    req.Header.Set("Authorization", "Bearer "+KEY)
    req.Header.Set("Content-Type", "application/json")
    res, err := http.DefaultClient.Do(req)
    if err != nil {
        return nil, 0, err
    }
    defer res.Body.Close()
    data, _ := io.ReadAll(res.Body)
    return data, res.StatusCode, nil
}

func Insert(collection string, doc any) (map[string]any, error) {
    b, code, err := do("POST", "/"+collection, doc)
    if err != nil {
        return nil, err
    }
    if code != 201 {
        return nil, fmt.Errorf("insert %d: %s", code, string(b))
    }
    var out map[string]any
    json.Unmarshal(b, &out)
    return out, nil
}
```

